7	function parseCellKey(key: string): Cell {
8	  const [xStr, yStr] = key.split(",");
9	  return [Number(xStr), Number(yStr)];
10	}
11	
12	export function nextGeneration(cells: Cell[]): Cell[] {
13	  const liveSet = new Set<string>();
14	  for (const [x, y] of cells) {
15	    liveSet.add(cellKey(x, y));
16	  }
17	
18	  // Count neighbors for every cell that could potentially be alive in the next generation.
19	  // These are the live cells themselves and any dead cell adjacent to a live cell.
20	  const neighborCounts = new Map<string, number>();
21	
22	  for (const [x, y] of cells) {
23	    for (let dx = -1; dx <= 1; dx++) {
24	      for (let dy = -1; dy <= 1; dy++) {
25	        if (dx === 0 && dy === 0) continue;
26	        const nx = x + dx;
27	        const ny = y + dy;
28	        const key = cellKey(nx, ny);
29	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
30	      }
31	    }
32	  }
33	
34	  const result: Cell[] = [];
35	  for (const [key, count] of neighborCounts) {
36	    const isAlive = liveSet.has(key);
37	    if (isAlive && (count === 2 || count === 3)) {
38	      result.push(parseCellKey(key));
39	    } else if (!isAlive && count === 3) {
40	      result.push(parseCellKey(key));
41	    }
42	  }
43	
44	  return result;
45	}
